INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00679', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '「面對電腦的運算能力每兩年就會倍增的飆速發展，我們的社會結構一直處於落後科技發展的狀 態，唯一的方法就是增加社會的適應力，也就是要使學習的效益達到最佳化，並將創新特質運用到 文化與社會結構上，破除因循僵化、講求靈活應變，以縮短從錯誤學習的時間。大學課程的推陳出 新也日益加快，有些課程甚至已標上時效。而隨著創新週期愈來愈短，學習適應的時間愈來愈少， 我們所面對的穩定狀態也有了變化，只有不穩定的固定狀態以及偶爾不穩定狀態的差異，新的穩定 狀態必定是動態穩定，就像騎腳踏車一樣，必須在雙腳不停地踩動下一直前進。」 根據上文，說明正確的選項是：', '["人類社會的結構總是無法跟上電腦運算能力的迅速發展", "提高學習效益可增加社會的整體適應力，維持靜態穩定", "行政機關以穩定為要，避免因創新融入而帶來擾動不安", "為了符應社會變動的需求，大學開設時效課程將成為一種趨勢 最佳適應力表現在失敗後能快速修正，並維持動態平衡的前進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00680', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-01c5eaab', 'sub-elementary-e0adf6cd-05', NULL, 'single_choice', '下列選項，適合平行機關間使用的是：', '["「檢陳」、「附送」", "「希查照」、「附送」", "「請查照」、「附送」", "「請查照」、「希查照」 「請查照」、「敬表同意」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00681', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '丙老師賞罰分明，同時也採用連坐法以強勢進行班級經營。從懲罰哲學的觀點看來，丙老師的連坐法違 反了下列何種懲罰要件？', '["確有犯過者", "罪證確鑿有據", "為進行社會控制而實施", "主客體為具有健全意識之人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00682', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '甲和乙都想成為一位教師，甲認為當老師是他的使命，乙則是希望有穩定工作可以改善家境。甲和乙想 當老師的想法分別符應了下列何種教育目的的主張？', '["甲：生活預備說；乙：宗教來生說", "甲：內在目的說；乙：生活預備說", "甲：生活預備說；乙：內在目的說", "甲：宗教來生說；乙：內在目的說"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00683', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何種教學法係源於廿世紀美國，主張由師生共同立下契約，讓學生依據自己的進度加以學習？', '["巴達維亞制（Bataviaplan）", "道爾頓制（Daltonplan）", "文納卡制（Winnetkaplan）", "劍橋制（Cambridgeplan）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00684', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列那一位西方教育學者提出課程設計的集中與相關原則，強調知識的統整學習？', '["赫爾巴特（J.Herbart）", "裴斯塔洛齊（J.Pestalozzi）", "康美紐斯（J.Comenius）", "盧梭（J.J.Rousseau）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00685', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '乙老師經常在課堂上，鼓勵同學要有「吾愛吾師，吾更愛真理」的學習精神，勇敢地探求學問。他的鼓 勵之語，係出自下列何位學者？', '["亞里斯多德（Aristotle）", "西塞洛（M.T.Cicero）", "菲希特（J.G.Fichte）", "路德（M.Luther）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00686', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「十年樹木，百年樹人。」這種說法較接近下列何種教育隱喻？', '["接生", "塑造", "雕刻", "生長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00687', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-111-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '促進社會進步，引領社會發展，是屬於下列何種教育功能？', '["個人功能", "家庭功能", "社會功能", "國家功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:41+00:00", "source_pdf_sha1": "cf56b931b4aa", "answer_pdf_sha1": "00d7ab252a18", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
